document.addEventListener("DOMContentLoaded",()=>{const mobileMenuContainer=document.querySelector(".mobile-menu-container");const mobileNavOverlay=document.getElementById("mobile-nav-overlay");const hamburgerIcon=document.querySelector(".mobile-menu-toggle");let touchstartX=0;let touchendX=0;const swipeThreshold=50;if(mobileMenuContainer&&mobileNavOverlay&&hamburgerIcon){mobileMenuContainer.addEventListener("touchstart",e=>{touchstartX=e.changedTouches[0].screenX});mobileMenuContainer.addEventListener("touchend",e=>{touchendX=e.changedTouches[0].screenX;handleGesture()});function handleGesture(){if(mobileMenuContainer.classList.contains("active")){if(touchendX>touchstartX+swipeThreshold){closeMobileMenu()}}}function closeMobileMenu(){mobileMenuContainer.classList.remove("active");mobileNavOverlay.classList.remove("active");document.body.classList.remove("menu-open");if(hamburgerIcon){hamburgerIcon.classList.remove("open");hamburgerIcon.setAttribute("aria-expanded","false")}}}});